mapper.select:
select id,comment_place_name,max(comment_time) as comment_time ,avg(comment_score) as comment_score
    from scenic_comment_info
    WHERE comment_time between #{startTime} and #{endTime}
    GROUP BY comment_place_name
    ORDER BY comment_score desc

        limit #{item}

select avg(comment_score)
    from scenic_comment_info
    where comment_time between #{beforeTime} and #{startTime} and comment_place_name = #{commentPlaceName}

select avg(comment_score)
    from scenic_comment_info
    where comment_time between #{startTime} and #{endTime}

select count(*)
    from scenic_comment_info
    where comment_type = 1 and comment_time between #{startTime} and #{endTime}

select count(*)
    from scenic_comment_info
    where comment_type = 0 and comment_time between #{startTime} and #{endTime}

select avg(comment_score)
    from scenic_comment_info
    where comment_place_name = #{commentPlaceName}
        and comment_time between #{startTime} and #{endTime}

select count(*)
    from scenic_comment_info
    where comment_type = 1
        and comment_place_name = #{commentPlaceName}
        and comment_time between #{startTime} and #{endTime}

select count(*)
    from scenic_comment_info
    where comment_type = 0
        and comment_place_name = #{commentPlaceName}
        and comment_time between #{startTime} and #{endTime}
